以下是一个使用localStorage缓存资源的示例代码：

```javascript
const loader = new THREE.GLTFLoader();

function loadGLTFModel(url) {
  // 检查缓存是否存在
  const cacheData = localStorage.getItem(url);
  if (cacheData !== null) {
    const gltf = JSON.parse(cacheData);
    const theObject = gltf.scene;
    addToScene(theObject);
    // 如果模型存在动画，则播放动画
    if (gltf.animations && gltf.animations.length) {
      const mixer = new THREE.AnimationMixer(theObject);
      for (let i = 0; i < gltf.animations.length; i++) {
        const animation = gltf.animations[i];
        const action = mixer.clipAction(animation);
        action.play();
      }
    }
    return;
  }

  // 模型未缓存，需要重新加载
  loader.load(url, function(gltf) {
    const theObject = gltf.scene;
    addToScene(theObject);

    // 如果模型存在动画，则播放动画
    if (gltf.animations && gltf.animations.length) {
      const mixer = new THREE.AnimationMixer(theObject);
      for (let i = 0; i < gltf.animations.length; i++) {
        const animation = gltf.animations[i];
        const action = mixer.clipAction(animation);
        action.play();
      }
    }

    // 将加载的数据存入缓存
    localStorage.setItem(url, JSON.stringify(gltf));
  });
}

function addToScene(object) {
  // 添加到场景中
  scene.add(object);
}
```

在此示例中，我们使用localStorage来缓存已经加载的GLTF模型。如果模型的数据存在于缓存中，我们将直接从缓存中获取并添加到场景中。如果缓存不存在或者已过期，则重新加载模型，将其添加到场景中，然后将其数据存入缓存，以便下次可以从缓存中获取。注意，这种缓存策略只适用于不会发生变化的模型。如果模型包含一些动态生成的内容（如纹理贴图），则需要使用其他缓存策略。

