```javascript
const loaderGLTF = new THREE.GLTFLoader();

function loadGLTFModel(url) {
  // 检查缓存是否存在
  const cacheData = localStorage.getItem(url);
  if (cacheData !== null) {
    const gltf = JSON.parse(cacheData);
    const theObject = gltf.scene;
    removeFromScene();
    addToScene(theObject);

    // 调整大小，设置居中
    setCenter(theObject);

    return;
  }

  // 模型未缓存，需要重新加载
  loaderGLTF.load(
    url,
    function(gltf) {
      const theObject = gltf.scene;
      removeFromScene();
      addToScene(theObject);

      // 调整大小，设置居中
      setCenter(theObject);

      // 将加载的数据存入缓存
      localStorage.setItem(url, JSON.stringify(gltf));
    },
    function(xhr) {
      // 加载进度回调
      const progress = Math.round((xhr.loaded / xhr.total) * 100);
      console.log(`${progress}% loaded`);
    },
    function(error) {
      // 加载错误回调
      console.error(`An error happened: ${error}`);
    }
  );
}

function removeFromScene() {
  scene.remove(theObject);
}

function addToScene(object) {
  scene.add(object);
}

function setCenter(object) {
  // 调整大小
  const box = new THREE.Box3().setFromObject(object);
  const size = box.getSize(new THREE.Vector3()).length();
  const scale = 1.0 / size;
  object.scale.set(scale, scale, scale);

  // 设置居中
  const center = box.getCenter(new THREE.Vector3());
  object.position.sub(center.multiplyScalar(scale));
}
```

